# Combine all words
ALL_WORDS = list(WORDS) + list(ADDITIONAL_WORDS)

print(f"Total word entries: {len(ALL_WORDS)}")

# Validate no duplicates
words_set = set(w[0].lower() for w in ALL_WORDS)
print(f"Unique words: {len(words_set)}")

# Export as importable constant
if __name__ == "__main__":
    import json, os
    out_path = os.path.join(os.path.dirname(__file__), 'core3000_words.json')
    data = []
    for w in ALL_WORDS:
        data.append({
            "word": w[0], "pos": w[1], "level": w[2], "freq": w[3],
            "meaning_en": w[4], "meaning_ar": w[5], "pronunciation": w[6],
            "synonyms": w[7], "antonyms": w[8],
            "collocations": w[9], "example": w[10]
        })
    with open(out_path, 'w', encoding='utf-8') as f:
        json.dump(data, f, ensure_ascii=False, indent=2)
    print(f"Exported {len(data)} words to {out_path}")
